// Extract Template Info + Select Topic - REJECTION-AWARE VERSION
// FIXED: Now reads from input when in rejection loop, otherwise from Workflow Configuration1

const existingPosts = $input.all();

if (!existingPosts || existingPosts.length === 0) {
  throw new Error('No existing posts found to extract template info');
}

const firstPost = existingPosts[0].json;

// Get rejection data - check input first (from rejection loop), then fallback to Workflow Configuration1
const inputData = $input.first().json;
const upstreamData = inputData.rejectionCount !== undefined && inputData.rejectionCount !== null
  ? inputData  // From rejection loop (Record Topic Rejection Feedback1)
  : ($('Workflow Configuration1').first()?.json || {});  // Initial run

const rejectionCount = upstreamData.rejectionCount || 0;
let previouslyRejectedTopics = [];
try {
  previouslyRejectedTopics = JSON.parse(upstreamData.previouslyRejectedTopics || '[]');
} catch (e) {
  previouslyRejectedTopics = [];
}

console.log('🔄 Rejection count:', rejectionCount);
console.log('🚫 Previously rejected topics:', previouslyRejectedTopics.length);

// Extract template info
const templateInfo = {
  post_format: firstPost.format || 'standard',
  template: firstPost.template || '',
  comment_status: firstPost.comment_status || 'open',
  ping_status: firstPost.ping_status || 'open',
  featured_media: firstPost.featured_media || 0
};

// Get existing post titles for duplicate checking
const existingTitles = existingPosts.map(p => {
  const title = p.json.title?.rendered || p.json.title || '';
  return title.toLowerCase().trim();
}).filter(Boolean);

console.log('📋 Extracted template info:', JSON.stringify(templateInfo, null, 2));
console.log('🔍 Found', existingTitles.length, 'existing posts');

// EXPANDED: List of potential topics (Hebrew) - 31 topics total
const topics = [
  `חובת הדיווח של הישראלים ל-IRS: FBAR, FATCA ו-Form 8938`,
  `הסכם המס בין ישראל לארה"ב: איך לנצל את הטבות המס ומתי להגיש Form 8833`,
  `מיסוי הכנסות השקעה: דיבידנדים, ריבית ורווחי הון`,
  `מיסוי עסקים דו-תושבים: חברות ישראליות עם פעילות בארה"ב`,
  `עסקאות נדל"ן ומס: רכישה ומכירה של נכסים בארה"ב`,
  `חשבונות פרישה: 401k, IRA וקרן השתלמות`,
  `שינויים בחוקי המס 2025: מה חדש לישראלים-אמריקאים`,
  `מסי מדינה: חובות לישראלים שאינם תושבי ארה"ב`,
  `מיסוי עיזבון ומס מתנות: תכנון עיזבון לישראלים-אמריקאים`,
  `אסטרטגיות תכנון מס לאזרחים כפולים`,
  `דיווח על חשבונות בנק זרים: FBAR - כל מה שצריך לדעת`,
  `Form 1116: זיכוי מס זר למשקיעים ישראלים`,
  `מיסוי עבודה מרחוק: ישראלים העובדים לחברות אמריקאיות`,
  `תיקון מעברי מס: איך להגיש 1040X ומה הסיכונים בהעדר תיקון`,
  `פטור מניכוי במקור: W-8BEN ו-W-8BEN-E`,
  `מיסוי רווחים מהשקעות נדל"ן: משקיעים ישראלים בארה"ב`,
  `תשלומי פנסיה ומס: ישראלים המקבלים פנסיה אמריקאית`,
  `מיסוי הכנסות מביטוח חיים: פוליסות אמריקאיות לישראלים`,
  `תכנון מס למשפחות דו-לאומיות: אסטרטגיות לחיסכון`,
  `מיסוי מטבעות קריפטו: ביטקוין, מכירות, החזקות, כריה וסטייקינג`,
  `מיסוי אופציות עובדים: RSU, ISO ו-NSO - מדריך מלא`,
  `דיווח על קרנות פנסיה וקופות גמל ישראליות בטפסי מס אמריקאיים`,
  `עצמאיים אמריקאים בישראל: האם חייבים במס עצמאות (Self-Employment Tax)?`,
  `חובות הגשת דוחות מס לילדים בעלי אזרחות אמריקאית`,
  `ויתור על אזרחות אמריקאית: השלכות מס ושיקולים משפחתיים`,
  `מיסוי עסקים מקוונים: Amazon, Etsy, Shopify ו-eCommerce`,
  `השלכות מס של מחילת חוב - כולל טופס 1099-C`,
  `סגירת LLC אמריקאית: תהליך, עלויות וחובות דיווח סופיות`,
  `כיצד לשלם את חובות המס ל-IRS: שיטות תשלום ותוכניות תשלומים`,
  `דיווח על תוכניות פנסיה ישראליות (קרן השתלמות, קופת גמל, פנסיה תקציבית)`,
  `מיסוי הכנסות פסיביות מחו"ל: דיבידנדים, ריבית ודמי שכירות`
];

// Filter out topics that match existing posts (improved duplicate detection)
let availableTopics = topics.filter(topic => {
  const topicLower = topic.toLowerCase();
  const topicKeywords = topicLower.split(/[\s:,-]+/).filter(w => w.length > 3);

  return !existingTitles.some(existingTitle => {
    const matchingKeywords = topicKeywords.filter(keyword => existingTitle.includes(keyword));
    return matchingKeywords.length >= 2;
  });
});

// ALSO filter out previously rejected topics in this session
if (previouslyRejectedTopics.length > 0) {
  availableTopics = availableTopics.filter(topic => 
    !previouslyRejectedTopics.includes(topic)
  );
  console.log('📊 After rejection filter:', availableTopics.length, 'topics remain');
}

console.log('📊 Available topics after all filtering:', availableTopics.length, 'out of', topics.length);

// IMPROVED ROTATION: Use rejection count as offset to get different topic each rejection
const executionId = $execution?.id || 'default';
const timestamp = Date.now();
const baseSeed = parseInt(executionId.replace(/[^0-9]/g, '').slice(-6) || '0', 10) + Math.floor(timestamp / (1000 * 60 * 60 * 24));
// Add rejection count to seed so each rejection selects a DIFFERENT topic
const rotationSeed = baseSeed + rejectionCount;

let selectedTopic;

if (availableTopics.length > 0) {
  const topicIndex = rotationSeed % availableTopics.length;
  selectedTopic = availableTopics[topicIndex];
  console.log(`🎯 Selected topic (index ${topicIndex}/${availableTopics.length}, rejection #${rejectionCount}):`, selectedTopic);
} else {
  // All topics exhausted - use full list with offset
  const topicIndex = rotationSeed % topics.length;
  selectedTopic = topics[topicIndex];
  console.log(`⚠️ All topics covered/rejected, cycling full list (index ${topicIndex}):`, selectedTopic);
}

console.log('🎯 Final selected topic:', selectedTopic);

return [{
  json: {
    ...templateInfo,
    topic: selectedTopic,
    existingPostsCount: existingTitles.length,
    availableTopicsCount: availableTopics.length,
    rotationIndex: rotationSeed % (availableTopics.length || topics.length),
    rejectionCount: rejectionCount,
    previouslyRejectedTopics: previouslyRejectedTopics
  }
}];

// Format Topic Selection Message - Creates Slack message for topic approval
const extractData = $input.first().json;

const selectedTopic = extractData.topic || 'No topic selected';
const existingPostsCount = extractData.existingPostsCount || 0;
const rejectionCount = extractData.rejectionCount || 0;
const recentTopics = extractData.recentTopics || [];

// Show rejection context if this is a re-selection
const rejectionContext = rejectionCount > 0 
  ? `\n\n🔄 *This is selection attempt #${rejectionCount + 1}* (previous topic was rejected)\n` 
  : '';

const slackMessage = `🎯 *TOPIC SELECTION FOR NEXT ARTICLE*${rejectionContext}

*Selected Topic:*
${selectedTopic}

${recentTopics.length > 0 ? `*Recent Topics Published (Last ${Math.min(recentTopics.length, 5)}):*\n${recentTopics.slice(0, 5).map((t, i) => `${i + 1}. ${t}`).join('\n')}\n` : ''}

*Instructions:*
• Click "✅ Approve Topic" to proceed with this topic
• Click "✏️ Modify Topic" to suggest a different topic or make changes

💡 *You can add notes or insights in the text field below before clicking any button.*
These notes will be included in the AI prompt to guide content generation.

_Automated with [this n8n workflow](https://tax4usllc.app.n8n.cloud/workflow/cHuJmIz5MVFAjP2Q)_`;

return {
  json: {
    ...extractData,
    slackMessage: slackMessage,
    selectedTopic: selectedTopic,
    originalTopic: selectedTopic,
    existingPostsCount: existingPostsCount
  }
};

// Process Topic Approval - OPTIMIZED VERSION + REJECTION LIMIT
// Handles user response from Slack topic approval
// ✅ FIXED: Added maximum rejection limit (5 rejections)

const slackResponse = $input.first().json;

// Extract decision from Slack response
const approved = slackResponse.data?.approved || false;
const feedback = slackResponse.data?.feedback || slackResponse.data?.text || slackResponse.feedback || '';
const decision = slackResponse.data?.decision || slackResponse.decision || (approved ? 'approve' : 'modify');

// Get data from Format Topic Selection Message ONCE (optimized)
const formatData = $('Format Topic Selection Message1').first().json;
const originalTopic = formatData.selectedTopic || formatData.topic || 'US-Israeli tax topics';
const rejectionCount = formatData.rejectionCount || 0;
let previouslyRejectedTopics = formatData.previouslyRejectedTopics || [];

// ✅ FIXED: Maximum rejection limit
const MAX_REJECTIONS = 5;
if (rejectionCount >= MAX_REJECTIONS) {
  console.error(`❌ Maximum rejection limit reached (${MAX_REJECTIONS}). Stopping workflow.`);
  throw new Error(`Maximum topic rejections reached (${MAX_REJECTIONS}). Please review topic selection process or approve a topic manually.`);
}

console.log('📋 Topic Approval Decision:', decision);
console.log('💬 User Feedback:', feedback.substring(0, 100) + (feedback.length > 100 ? '...' : ''));
console.log('✅ Approved:', approved);
console.log('🔄 Rejection count:', rejectionCount, '/', MAX_REJECTIONS);

// Determine final topic based on decision
let finalTopic = originalTopic;
let topicModified = false;
let userNotes = '';
let topicSkipped = false;

// Check if user wants to skip (reject)
const feedbackLower = (feedback || '').toLowerCase().trim();
const wantsToSkip = decision === 'skip' || 
                    decision === 'Skip This Topic' || 
                    feedbackLower === 'skip' || 
                    feedbackLower.startsWith('skip ') ||
                    (!approved && !feedback.trim()); // Disapprove with no feedback = skip

if (wantsToSkip || (!approved && decision !== 'approve')) {
  // User wants to skip/reject this topic
  // Add to rejected list so next selection skips it
  if (!previouslyRejectedTopics.includes(originalTopic)) {
    previouslyRejectedTopics = [...previouslyRejectedTopics, originalTopic];
  }

  const newRejectionCount = rejectionCount + 1;
  console.log(`❌ Topic skipped/rejected by user (rejection #${newRejectionCount}/${MAX_REJECTIONS})`);

  // Check limit before returning
  if (newRejectionCount >= MAX_REJECTIONS) {
    throw new Error(`Maximum topic rejections reached (${MAX_REJECTIONS}). Please review topic selection process.`);
  }

  return [{
    json: {
      topicSkipped: true,
      originalTopic: originalTopic,
      userNotes: feedback,
      skipReason: feedback || 'User skipped topic',
      rejectionCount: newRejectionCount,
      previouslyRejectedTopics: previouslyRejectedTopics,
      // Pass through template info
      post_format: formatData.post_format,
      template: formatData.template,
      comment_status: formatData.comment_status,
      ping_status: formatData.ping_status,
      featured_media: formatData.featured_media,
      existingPostsCount: formatData.existingPostsCount
    }
  }];
} else if (decision === 'approve' || approved === true) {
  finalTopic = originalTopic;
  userNotes = feedback;
  topicSkipped = false;
  console.log('✅ Topic approved:', finalTopic);
} else if (decision === 'modify' || decision === 'Modify Topic') {
  if (feedback && feedback.trim().length > 10) {
    finalTopic = feedback.trim();
    topicModified = true;
    topicSkipped = false;
    console.log('✏️ Topic modified by user:', finalTopic);
  } else {
    finalTopic = originalTopic;
    topicSkipped = false;
    console.log('⚠️ Modify requested but no new topic provided, using original');
  }
  userNotes = feedback;
} else {
  finalTopic = originalTopic;
  userNotes = feedback;
  topicSkipped = false;
}

// Return data with final topic and user notes for AI Agent
return [{
  json: {
    ...formatData,
    topic: finalTopic,
    originalTopic: originalTopic,
    topicModified: topicModified,
    topicSkipped: topicSkipped,
    userNotes: userNotes,
    approvalDecision: decision,
    approved: approved,
    rejectionCount: rejectionCount,
    previouslyRejectedTopics: previouslyRejectedTopics
  }
}];

// Parse AI Response - FIXED: Improved JSON parsing to prevent content truncation
// Handles Claude's thinking mode output structure + various JSON formats
// Now converts ## and ### markdown to proper wp:heading blocks for SEO
// CRITICAL FIX: Better JSON extraction to prevent content being cut off
// ✅ NEW: Detects Hebrew and sets isHebrewPost for sub-category selection
// ✅ IMPROVED: Better error handling and field extraction with multiple fallbacks

const inputData = $input.first().json;

// Get topic from input chain
let topic = inputData.topic || '';
if (!topic) {
  try {
    const processTopicData = $('Process Topic Approval1').first()?.json || {};
    topic = processTopicData.topic || processTopicData.selectedTopic || topic;
  } catch (e) {
    console.log('⚠️ Could not access Process Topic Approval1 node');
  }
}

// === STEP 1: Extract JSON from AI Agent output ===
let jsonText = null;

console.log('🔍 Input data keys:', Object.keys(inputData));
console.log('🔍 Output type:', typeof inputData.output);

if (Array.isArray(inputData.output)) {
  console.log('📦 Output is array with', inputData.output.length, 'items');
  for (const item of inputData.output) {
    if (item.type === 'text' && item.text) {
      jsonText = item.text;
      console.log('✅ Found text item, length:', jsonText.length);
      break;
    }
  }
  if (!jsonText) {
    const textItem = inputData.output.find(item => item.text && typeof item.text === 'string');
    if (textItem) jsonText = textItem.text;
  }
  // Also check for direct content in array items
  if (!jsonText) {
    for (const item of inputData.output) {
      if (typeof item === 'string') {
        jsonText = item;
        break;
      } else if (item.content && typeof item.content === 'string') {
        jsonText = item.content;
        break;
      }
    }
  }
} else if (typeof inputData.output === 'string') {
  jsonText = inputData.output;
} else if (inputData.output && typeof inputData.output === 'object') {
  if (inputData.output.title && inputData.output.content) {
    const parsed = inputData.output;
    const title = (parsed.title || '').trim();
    let content = (parsed.content || '').trim();
    const excerpt = (parsed.excerpt || '').trim();
    let focusKeyword = (parsed.focusKeyword || '').trim();
    const seoTitle = (parsed.seoTitle || parsed.title || '').trim();
    const seoDescription = (parsed.seoDescription || parsed.excerpt || '').trim();

    if (!title) throw new Error('AI response missing title');
    if (!content) throw new Error('AI response missing content');
    if (!focusKeyword) {
      const words = title.split(/[\s:,\-–—]+/).filter(w => w.length > 2);
      focusKeyword = words.slice(0, 4).join(' ').substring(0, 50);
    }
    content = content.replace(/\[IMAGE\s+PLACEMENT[^\]]*\]/gi, '').replace(/\[תמונת\s+מיקום[^\]]*\]/gi, '').trim();
    return buildGutenbergOutput(title, content, excerpt, focusKeyword, seoTitle, seoDescription, topic);
  }
  jsonText = JSON.stringify(inputData.output);
}

if (!jsonText && inputData.text) jsonText = inputData.text;
if (!jsonText && inputData.response) {
  jsonText = typeof inputData.response === 'string' ? inputData.response : inputData.response.text;
}
if (!jsonText && inputData.message) jsonText = inputData.message;
if (!jsonText && inputData.content) jsonText = inputData.content;

if (!jsonText) {
  console.error('❌ No output found. Available keys:', Object.keys(inputData));
  console.error('❌ Input data sample:', JSON.stringify(inputData).substring(0, 500));
  throw new Error('No output from AI Agent. Check input structure.');
}

console.log('📝 JSON text length:', jsonText.length);
console.log('📝 JSON text preview (first 500 chars):', jsonText.substring(0, 500));

// === STEP 2: Parse JSON - IMPROVED to handle large content ===
let parsed = null;
let parseMethod = 'unknown';

try {
  let cleaned = jsonText.replace(/```json\s*/gi, '').replace(/```javascript\s*/gi, '').replace(/```\s*/g, '').trim();

  // IMPROVED: Find JSON object boundaries more accurately
  // Look for opening brace, then find matching closing brace
  const firstBrace = cleaned.indexOf('{');
  if (firstBrace === -1) throw new Error('No JSON object found');

  let braceCount = 0;
  let jsonEnd = -1;
  for (let i = firstBrace; i < cleaned.length; i++) {
    if (cleaned[i] === '{') braceCount++;
    if (cleaned[i] === '}') {
      braceCount--;
      if (braceCount === 0) {
        jsonEnd = i + 1;
        break;
      }
    }
  }

  if (jsonEnd > firstBrace) {
    let jsonStr = cleaned.substring(firstBrace, jsonEnd);
    // Clean up common JSON issues
    jsonStr = jsonStr.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']').replace(/[\u0000-\u001F]/g, ' ');
    parsed = JSON.parse(jsonStr);
    parseMethod = 'brace-matching';
    console.log('✅ Successfully parsed JSON via brace-matching, content length:', (parsed.content || '').length);
  } else {
    // Fallback to regex match
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      let jsonStr = jsonMatch[0].replace(/,\s*}/g, '}').replace(/,\s*]/g, ']').replace(/[\u0000-\u001F]/g, ' ');
      parsed = JSON.parse(jsonStr);
      parseMethod = 'regex-fallback';
      console.log('✅ Parsed JSON via regex, content length:', (parsed.content || '').length);
    } else {
      parsed = JSON.parse(cleaned);
      parseMethod = 'direct-parse';
      console.log('✅ Parsed JSON directly, content length:', (parsed.content || '').length);
    }
  }
} catch (e) {
  console.error('❌ JSON parse failed:', e.message);
  console.error('📝 Parse method attempted:', parseMethod);
  console.error('📝 Attempting regex extraction...');

  // IMPROVED: Better regex extraction for large content fields
  const extractField = (fieldName) => {
    // Try multiple patterns for better extraction
    const patterns = [
      // Standard JSON: "field": "value" (handles escaped quotes and newlines) - non-greedy
      new RegExp(`"${fieldName}"\\s*:\\s*"((?:[^"\\\\]|\\\\[\\s\\S])*?)"`, 's'),
      // Standard JSON: "field": "value" - greedy (for very long content)
      new RegExp(`"${fieldName}"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*?)"`, 's'),
      // Single quotes: 'field': 'value'
      new RegExp(`'${fieldName}'\\s*:\\s*'((?:[^'\\\\]|\\\\[\\s\\S])*?)'`, 's'),
      // Without quotes: field: value
      new RegExp(`${fieldName}\\s*:\\s*"((?:[^"\\\\]|\\\\[\\s\\S])*?)"`, 's'),
      // Multiline with escaped quotes
      new RegExp(`"${fieldName}"\\s*:\\s*"([^"\\n]*(?:\\.[^"\\n]*)*)"`, 's'),
    ];

    for (const pattern of patterns) {
      try {
        const match = jsonText.match(pattern);
        if (match && match[1]) {
          let value = match[1]
            .replace(/\\n/g, '\n')
            .replace(/\\r/g, '\r')
            .replace(/\\t/g, '\t')
            .replace(/\\"/g, '"')
            .replace(/\\'/g, "'")
            .replace(/\\\\/g, '\\');
          if (value && value.trim().length > 0) {
            console.log(`✅ Extracted ${fieldName}, length:`, value.length);
            return value;
          }
        }
      } catch (e) {
        // Continue to next pattern
      }
    }

    console.warn(`⚠️ Could not extract ${fieldName}`);
    return '';
  };

  parsed = {
    title: extractField('title'),
    content: extractField('content'),
    excerpt: extractField('excerpt'),
    focusKeyword: extractField('focusKeyword'),
    seoTitle: extractField('seoTitle'),
    seoDescription: extractField('seoDescription')
  };

  console.log('📊 Extracted fields:');
  console.log('  - title length:', parsed.title.length);
  console.log('  - content length:', parsed.content.length);
  console.log('  - excerpt length:', parsed.excerpt.length);

  // If still no title or content, try to find them in the raw text
  if (!parsed.title || !parsed.content) {
    console.error('❌ Failed to extract required fields via regex');
    console.error('📝 Available in parsed object:', Object.keys(parsed));
    console.error('📝 Parsed object sample:', JSON.stringify(parsed).substring(0, 1000));

    // Last resort: try to extract from raw text using simpler patterns
    if (!parsed.title) {
      const titleMatch = jsonText.match(/title[\s:]*["']([^"']+)["']/i) || jsonText.match(/title[\s:]*([^\n,}]+)/i);
      if (titleMatch && titleMatch[1]) parsed.title = titleMatch[1].trim();
    }

    if (!parsed.content) {
      const contentMatch = jsonText.match(/content[\s:]*["']([^"']+)["']/i) || jsonText.match(/content[\s:]*([^\n,}]+)/i);
      if (contentMatch && contentMatch[1]) parsed.content = contentMatch[1].trim();
    }

    if (!parsed.title || !parsed.content) {
      throw new Error(`Failed to parse AI response - missing title or content. Title found: ${!!parsed.title}, Content found: ${!!parsed.content}. Parse method: ${parseMethod}. JSON preview: ${jsonText.substring(0, 200)}`);
    }
  }
}

// === STEP 3: Extract and validate fields ===
const title = (parsed.title || '').trim();
let content = (parsed.content || '').trim();
const excerpt = (parsed.excerpt || '').trim();
let focusKeyword = (parsed.focusKeyword || '').trim();
const seoTitle = (parsed.seoTitle || parsed.title || '').trim();
const seoDescription = (parsed.seoDescription || parsed.excerpt || '').trim();

console.log('📊 Final field lengths:');
console.log('  - title:', title.length);
console.log('  - content:', content.length);
console.log('  - excerpt:', excerpt.length);

if (!title || title.length === 0) {
  console.error('❌ Title is empty. Parsed object:', JSON.stringify(parsed).substring(0, 500));
  throw new Error('AI response missing title');
}
if (!content || content.length === 0) {
  console.error('❌ Content is empty. Parsed object:', JSON.stringify(parsed).substring(0, 500));
  throw new Error('AI response missing content');
}

if (content.length < 100) {
  console.warn('⚠️ Content seems very short (' + content.length + ' chars) - may be truncated');
}

if (!focusKeyword) {
  const words = title.split(/[\s:,\-–—]+/).filter(w => w.length > 2);
  focusKeyword = words.slice(0, 4).join(' ').substring(0, 50);
}

return buildGutenbergOutput(title, content, excerpt, focusKeyword, seoTitle, seoDescription, topic);

// === HELPER FUNCTION: Build Gutenberg Output with Markdown Conversion ===
function buildGutenbergOutput(title, content, excerpt, focusKeyword, seoTitle, seoDescription, topic = '') {
  content = content.replace(/\[IMAGE\s+PLACEMENT[^\]]*\]/gi, '').replace(/\[תמונת\s+מיקום[^\]]*\]/gi, '').trim();

  // ✅ NEW: Detect Hebrew language
  const hasHebrew = /[\u0590-\u05FF]/.test(title + content + excerpt + topic);
  console.log('🇮🇱 Hebrew detected:', hasHebrew);

  const escapeHtml = (str) => str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  const titleEscaped = escapeHtml(title);

  // Split content into paragraphs
