const extractValue = (val) => {
  if (val == null) return '';
  if (typeof val === 'string') return val;
  if (typeof val === 'object') {
    if (val.value !== undefined) return val.value;
    if (val.rendered !== undefined) return val.rendered;
    return JSON.stringify(val);
  }
  return String(val);
};

// === HELPER: Decode HTML entities ===
const decodeHtmlEntities = (str) => {
  if (!str || typeof str !== 'string') return str;
  // Decode common HTML entities
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/&#8217;/g, "'")
    .replace(/&#8218;/g, ',')
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"')
    .replace(/&#8222;/g, ',,')
    .replace(/&#8211;/g, '-')
    .replace(/&#8212;/g, '—')
    .replace(/&#8230;/g, '...')
    .replace(/&#160;/g, ' ')
    .replace(/&nbsp;/g, ' ');
};

// === HELPER: Proper HTML escape (for use in HTML content) ===
const escapeHtml = (str) => {
  if (!str || typeof str !== 'string') return '';
  // First decode any existing entities to avoid double-escaping
  let decoded = decodeHtmlEntities(str);
  // Then escape properly
  return decoded
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
};

