  const queryMatch = content.match(queryBlockRegex);
  if (!queryMatch) return content;

  let updatedAttrs = queryMatch[1]
    .replace(/"exclude":\[\]/, '"exclude":[' + excludePostId + ']')
    .replace(/"inherit":true/, '"inherit":false');

  return content.replace(queryBlockRegex, '<!-- wp:query ' + updatedAttrs + ' -->');
};

