const match = content.match(queryBlockRegex);

if (!match) return [{ json: { ...publishData, updatedContent: content, postId, skipExcludeUpdate: false } }];

let attrs = match[1];
if (/"exclude":\[\]/.test(attrs)) {
  attrs = attrs.replace(/"exclude":\[\]/, `"exclude":[${postId}]`);
} else if (!/"exclude":/.test(attrs)) {
  attrs = attrs.replace(/"inherit":(true|false)/, `"inherit":false,"exclude":[${postId}]`);
} else {
  attrs = attrs.replace(/"exclude":\[[^\]]*\]/, `"exclude":[${postId}]`);
}
attrs = attrs.replace(/"inherit":true/, '"inherit":false');

const updatedContent = content.replace(queryBlockRegex, `<!-- wp:query ${attrs} -->`);

return [{ json: { ...publishData, updatedContent, postId, skipExcludeUpdate: false } }];

