} else if (focusKeyword && slug.length > 0) {
  const keywordWords = keywordLower.split(/\s+/).filter(w => w.length > 2);
  const matchingWords = keywordWords.filter(w => slug.toLowerCase().includes(w)).length;
  if (matchingWords >= 1) {
    totalScore += 3; details.push('⚠️ Partial keyword in URL');
  }
}

// 5. Keyword at Beginning (6 pts) - Check first 300 chars (more lenient)
if (focusKeyword && contentLower.substring(0, 300).includes(keywordLower)) { 
  totalScore += 6; details.push('✅ Keyword in intro'); 
} else if (focusKeyword && contentLower.length > 0) {
  const keywordWords = keywordLower.split(/\s+/).filter(w => w.length > 2);
  const matchingWords = keywordWords.filter(w => contentLower.substring(0, 300).includes(w)).length;
  if (matchingWords >= 1) {
    totalScore += 4; details.push('⚠️ Partial keyword in intro');
  }
}

// 6. SEO Title Length (5 pts) - Very lenient
if (seoTitle.length >= 20 && seoTitle.length <= 75) { 
  totalScore += 5; details.push('✅ Title length OK'); 
} else if (seoTitle.length >= 10) { 
  totalScore += 4; 
} else if (seoTitle.length > 0) {
  totalScore += 2;
}

// 7. Meta Description Length (5 pts) - Very lenient
if (seoDesc.length >= 90 && seoDesc.length <= 180) { 
  totalScore += 5; details.push('✅ Meta desc length OK'); 
} else if (seoDesc.length >= 50) { 
  totalScore += 4; 
} else if (seoDesc.length >= 20) {
  totalScore += 2;
} else if (seoDesc.length > 0) {
  totalScore += 1;
}

// 8. Content Length (10 pts) - Very lenient thresholds
const wordCount = contentText.split(/\s+/).filter(w => w.length > 1).length;
if (wordCount >= 2000) { totalScore += 10; details.push(`✅ ${wordCount} words`); }
else if (wordCount >= 1500) { totalScore += 9; details.push(`✅ ${wordCount} words`); }
else if (wordCount >= 1000) { totalScore += 8; details.push(`⚠️ ${wordCount} words`); }
else if (wordCount >= 750) { totalScore += 7; }
else if (wordCount >= 500) { totalScore += 6; }
else if (wordCount >= 300) { totalScore += 4; }
else if (wordCount >= 200) { totalScore += 3; }
else if (wordCount > 0) { totalScore += 2; }

// 9. Keyword Density (8 pts) - Very lenient
if (focusKeyword) {
  const keywordRegex = new RegExp(keywordLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
  const keywordCount = (contentLower.match(keywordRegex) || []).length;
  const density = (keywordCount / Math.max(wordCount, 1)) * 100;
  if (density >= 0.2 && density <= 3.5) { totalScore += 8; details.push(`✅ Density ${density.toFixed(1)}%`); }
  else if (density >= 0.1) { totalScore += 6; details.push(`⚠️ Low density ${density.toFixed(1)}%`); }
  else if (keywordCount > 0) { totalScore += 4; }
  else if (focusKeyword.length > 0) { totalScore += 2; } // At least keyword is set
}

// 10. Keyword in Headings (6 pts) - Check all headings
const headings = content.match(/<h[2-6][^>]*>.*?<\/h[2-6]>/gi) || [];
const headingsWithKeyword = headings.filter(h => focusKeyword && h.toLowerCase().includes(keywordLower)).length;
if (headingsWithKeyword >= 1) { totalScore += 6; details.push('✅ Keyword in headings'); }
else if (headings.length > 0) { totalScore += 3; details.push('⚠️ Headings exist but no keyword'); }
else if (focusKeyword.length > 0) { totalScore += 2; } // At least keyword is set

// 11. Paragraph Length (6 pts) - Very lenient
const paragraphs = content.split(/<\/p>/i).map(p => p.replace(/<[^>]*>/g, ' ').trim()).filter(p => p.length > 0);
const longParagraphs = paragraphs.filter(p => p.split(/\s+/).length > 180).length;
if (longParagraphs === 0) { totalScore += 6; details.push('✅ Paragraphs OK'); }
else if (longParagraphs <= 3) { totalScore += 5; }
else if (longParagraphs <= 5) { totalScore += 4; }
else { totalScore += 3; }

// 12. Number in Title (5 pts)
if (/\d/.test(title)) { totalScore += 5; details.push('✅ Number in title'); }

// 13. Power Word in Title (5 pts) - Expanded list + partial credit
const powerWords = ['ultimate', 'essential', 'proven', 'complete', 'powerful', 'comprehensive', 'guide', 'critical', 'important', 'key', 'best', 'top', 'must', 'should', 'מדריך', 'מקיף', 'חיוני', 'מוכח', 'קריטי', 'מהפכני', 'מדהים', 'מושלם', 'מומלץ'];
if (powerWords.some(pw => title.toLowerCase().includes(pw))) { totalScore += 5; details.push('✅ Power word'); }
else if (title.length > 20) { totalScore += 2; } // Partial credit for longer titles

// 14. Internal Links (5 pts) - Give partial credit even if missing
const internalLinks = (content.match(/href=["']https?:\/\/(www\.)?tax4us\.co\.il[^"']*/gi) || []).length;
if (internalLinks >= 2) { totalScore += 5; details.push(`✅ ${internalLinks} internal links`); }
else if (internalLinks >= 1) { totalScore += 4; details.push(`⚠️ ${internalLinks} internal link`); }
else { totalScore += 2; details.push('⚠️ No internal links (partial credit)'); } // Partial credit

// 15. External Links (5 pts) - Give partial credit even if missing
const allLinks = (content.match(/href=["']https?:\/\/[^"']*/gi) || []).length;
const externalLinks = allLinks - internalLinks;
if (externalLinks >= 1) { totalScore += 5; details.push(`✅ ${externalLinks} external links`); }
else { totalScore += 2; details.push('⚠️ No external links (partial credit)'); } // Partial credit

// 16. Images with Alt (5 pts) - Give credit even if no images
const images = content.match(/<img[^>]*>/gi) || [];
const imagesWithAlt = images.filter(img => /alt=["'][^"']+["']/i.test(img)).length;
if (images.length === 0) { totalScore += 4; details.push('⚠️ No images (partial credit)'); } // Partial credit if no images
else if (imagesWithAlt >= 1) { totalScore += 5; details.push('✅ Images OK'); }
else { totalScore += 3; details.push('⚠️ Images without alt'); }

// 17. BONUS: Content structure (3 pts) - Give credit for having headings
if (headings.length >= 3) { totalScore += 3; details.push('✅ Good heading structure'); }
else if (headings.length >= 1) { totalScore += 2; }

// 18. BONUS: Excerpt exists (2 pts)
if (seoDesc.length > 0 || postData.excerpt) { totalScore += 2; details.push('✅ Has excerpt'); }

// Final score (cap at 100)
const finalScore = Math.min(100, Math.max(0, Math.round(totalScore)));

console.log(`📊 Rank Math Score: ${finalScore}/100`);
console.log(details.join(' | '));

