// Auto Assign Sub-Categories Based on Content Analysis
// ✅ FIXED: Strips HTML from content before analysis for better matching
// Uses keyword matching and content analysis to automatically select relevant sub-categories

const inputData = $input.first().json;
const parseData = inputData || {};
const subCategories = inputData.subCategories || [];

console.log('📂 Auto Assign Sub-Categories - Input data keys:', Object.keys(parseData));
console.log('📂 Available sub-categories:', subCategories.length);
console.log('📂 Sub-categories:', subCategories.map(c => c.name).slice(0, 5));

// ✅ FIXED: Strip HTML from content before analysis (like Assign Tags does)
const cleanContent = (parseData.content || '')
  .replace(/<!-- wp:[\s\S]*?-->/g, '')  // Remove Gutenberg comments
  .replace(/<[^>]*>/g, ' ')  // Remove HTML tags
  .replace(/\s+/g, ' ')  // Normalize whitespace
  .trim();

const title = (parseData.title || '').toLowerCase();
const content = cleanContent.toLowerCase();
const excerpt = (parseData.excerpt || '').toLowerCase();
const topic = (parseData.topic || '').toLowerCase();
const focusKeyword = (parseData.focusKeyword || '').toLowerCase();

console.log('📂 Analyzing content for sub-category assignment...');
console.log('📂 Title:', title.substring(0, 50));
console.log('📂 Content length (cleaned):', content.length);
console.log('📂 Focus keyword:', focusKeyword);

let selectedSubCategoryIds = [];
let selectedNames = [];
let matchScores = [];

// For each sub-category, calculate relevance score
for (const category of subCategories) {
  const categoryName = (category.name || '').toLowerCase();
  const categorySlug = (category.slug || '').toLowerCase();
  let score = 0;

  // Exact matches in title (highest weight)
  if (title.includes(categoryName) || title.includes(categorySlug)) {
    score += 10;
    console.log(`  ✅ Title match: ${category.name} (+10)`);
  }

  // Exact matches in focus keyword (high weight)
  if (focusKeyword.includes(categoryName) || focusKeyword.includes(categorySlug)) {
    score += 8;
    console.log(`  ✅ Keyword match: ${category.name} (+8)`);
  }

  // Exact matches in topic (high weight)
  if (topic.includes(categoryName) || topic.includes(categorySlug)) {
    score += 8;
    console.log(`  ✅ Topic match: ${category.name} (+8)`);
  }

  // Partial matches in title
  const titleWords = title.split(/[\s:,\-–—]+/);
  const categoryWords = categoryName.split(/[\s:,\-–—]+/);
  for (const cWord of categoryWords) {
    if (cWord.length > 3 && titleWords.some(tWord => tWord.includes(cWord) || cWord.includes(tWord))) {
      score += 5;
      console.log(`  ✅ Partial title match: ${category.name} (word: ${cWord}) (+5)`);
    }
  }

  // Matches in content (lower weight)
  if (content.includes(categoryName) || content.includes(categorySlug)) {
    score += 3;
    console.log(`  ✅ Content match: ${category.name} (+3)`);
  }

  // Matches in excerpt
  if (excerpt.includes(categoryName) || excerpt.includes(categorySlug)) {
    score += 2;
    console.log(`  ✅ Excerpt match: ${category.name} (+2)`);
  }

  // Store score
  matchScores.push({ category, score });
  if (score > 0) {
    console.log(`  📊 ${category.name}: score = ${score}`);
  }
}

// Sort by score (highest first)
matchScores.sort((a, b) => b.score - a.score);

console.log('📂 Top 5 match scores:', matchScores.slice(0, 5).map(m => `${m.category.name}: ${m.score}`));

// Select top 1-3 sub-categories (with score >= 5)
const threshold = 5;
const topMatches = matchScores.filter(m => m.score >= threshold);

console.log('📂 Matches above threshold (>=5):', topMatches.length);

// If we have good matches, use them (max 3)
if (topMatches.length > 0) {
  const selected = topMatches.slice(0, 3);
  for (const match of selected) {
    selectedSubCategoryIds.push(match.category.id);
    selectedNames.push(match.category.name);
    console.log(`✅ Auto-selected: ${match.category.name} (score: ${match.score})`);
  }
} else if (subCategories.length > 0) {
  // Fallback: if no good matches, select the first sub-category as default
  console.log('⚠️ No strong matches found (score >= 5), using first sub-category as default');
  console.log('⚠️ First sub-category:', subCategories[0].name, '(ID:', subCategories[0].id, ')');
  selectedSubCategoryIds.push(subCategories[0].id);
  selectedNames.push(subCategories[0].name);
} else {
  console.log('⚠️ No sub-categories available');
}

console.log('📂 Auto-selected sub-categories:', selectedNames);
console.log('📂 Selected IDs:', selectedSubCategoryIds);

// Return data with auto-selected sub-categories
return {
  json: {
    ...parseData,
    selectedSubCategoryIds: selectedSubCategoryIds,
    selectedSubCategoryNames: selectedNames,
    autoAssigned: true,
    subCategoryMatchScores: matchScores.map(m => ({
