  if (fetchNode && fetchNode.first()) {
    const categoriesData = fetchNode.first().json;
    if (Array.isArray(categoriesData)) {
      englishSubCategories = categoriesData.filter(cat => cat && cat.id && cat.name);
      console.log('✅ Got English sub-categories from Fetch English Sub-Categories:', englishSubCategories.length);
    } else if (categoriesData && categoriesData.id && categoriesData.name) {
      // Single category object
      englishSubCategories = [categoriesData];
      console.log('✅ Got single English sub-category from Fetch English Sub-Categories');
    }
  }
} catch (e) {
  console.log('⚠️ Could not access Fetch English Sub-Categories node:', e.message);
}

console.log('📂 Available English sub-categories:', englishSubCategories.length);

if (englishSubCategories.length === 0) {
  console.log('⚠️ No English sub-categories found - will use base categories only');
  // Return with base categories only
  return {
    json: {
      ...translatedData,
      categories: [22, 46], // English language + All You Need to Know
      selectedEnglishSubCategoryIds: [],
      selectedEnglishSubCategoryNames: [],
      autoAssignedEnglish: false
    }
  };
}

const title = (translatedData.title || '').toLowerCase();
const content = (translatedData.content || '').replace(/<!-- wp:[\s\S]*?-->/g, '').replace(/<[^>]*>/g, ' ').toLowerCase();
const excerpt = (translatedData.excerpt || '').toLowerCase();
const focusKeyword = (translatedData.focusKeyword || '').toLowerCase();

let selectedEnglishSubCategoryIds = [];
let selectedNames = [];
let matchScores = [];

// For each sub-category, calculate relevance score
for (const category of englishSubCategories) {
  const categoryName = (category.name || '').toLowerCase();
  const categorySlug = (category.slug || '').toLowerCase();
  let score = 0;

  // Exact matches in title (highest weight)
  if (title.includes(categoryName) || title.includes(categorySlug)) {
    score += 10;
  }

  // Exact matches in focus keyword (high weight)
  if (focusKeyword.includes(categoryName) || focusKeyword.includes(categorySlug)) {
    score += 8;
  }

  // Partial matches in title
  const titleWords = title.split(/\s+/);
  const categoryWords = categoryName.split(/\s+/);
  for (const cWord of categoryWords) {
    if (cWord.length > 3 && titleWords.some(tWord => tWord.includes(cWord) || cWord.includes(tWord))) {
      score += 5;
    }
  }

  // Matches in content (lower weight)
  if (content.includes(categoryName) || content.includes(categorySlug)) {
    score += 3;
  }

  // Matches in excerpt
  if (excerpt.includes(categoryName) || excerpt.includes(categorySlug)) {
    score += 2;
  }

  // Store score
  matchScores.push({ category, score });
}

// Sort by score (highest first)
matchScores.sort((a, b) => b.score - a.score);

// Select top 1-3 sub-categories (with score >= 5)
const threshold = 5;
const topMatches = matchScores.filter(m => m.score >= threshold);

// If we have good matches, use them (max 3)
if (topMatches.length > 0) {
  const selected = topMatches.slice(0, 3);
  for (const match of selected) {
    selectedEnglishSubCategoryIds.push(match.category.id);
    selectedNames.push(match.category.name);
    console.log(`✅ Auto-selected English sub-category: ${match.category.name} (score: ${match.score})`);
  }
} else if (englishSubCategories.length > 0) {
  // Fallback: if no good matches, select the first sub-category as default
  console.log('⚠️ No strong matches found, using first English sub-category as default');
  selectedEnglishSubCategoryIds.push(englishSubCategories[0].id);
  selectedNames.push(englishSubCategories[0].name);
} else {
  console.log('⚠️ No English sub-categories available');
}

console.log('📂 Auto-selected English sub-categories:', selectedNames);
console.log('📂 Selected IDs:', selectedEnglishSubCategoryIds);

// Build categories array: English language (22) + All You Need to Know (46) + sub-categories
const englishCategories = [22, 46];
if (selectedEnglishSubCategoryIds.length > 0) {
  englishCategories.push(...selectedEnglishSubCategoryIds);
  console.log('📂 Final English categories array:', englishCategories);
} else {
  console.log('⚠️ No sub-categories selected - using base categories only');
}

// Return data with auto-selected sub-categories
return {
  json: {
    ...translatedData,
    categories: englishCategories,
    selectedEnglishSubCategoryIds: selectedEnglishSubCategoryIds,
    selectedEnglishSubCategoryNames: selectedNames,
    autoAssignedEnglish: true
  }
};

// Extract Featured Image URL and merge with post data
const inputData = $input.first().json;
const postData = $('Link Polylang Translations1').first().json;

let featuredImageUrl = '';

// Extract URL from media response (if HTTP Request succeeded)
if (inputData && inputData.source_url) {
  featuredImageUrl = inputData.source_url;
  console.log('✅ Got featured image URL from source_url:', featuredImageUrl);
} else if (inputData && inputData.guid && inputData.guid.rendered) {
  featuredImageUrl = inputData.guid.rendered;
  console.log('✅ Got featured image URL from guid:', featuredImageUrl);
} else if (inputData && inputData.url) {
  featuredImageUrl = inputData.url;
  console.log('✅ Got featured image URL from url field:', featuredImageUrl);
} else {
  console.log('⚠️ No featured image URL found in media response');
}

// Return merged data
return [{
  json: {
    ...postData,
    featured_image_url: featuredImageUrl,
    image_url: featuredImageUrl || postData.image_url || '',
    english_post_id: postData.id || postData.postId || 0,
    english_post_title: postData.title?.raw || postData.title?.rendered || postData.title || '',
    english_post_content: postData.content?.raw || postData.content?.rendered || postData.content || '',
    english_post_excerpt: postData.excerpt?.raw || postData.excerpt?.rendered || postData.excerpt || '',
    english_post_url: postData.link || postData.url || ''
  }
}];

// Parse and validate LinkedIn post from AI output
const inputData = $input.first().json;

console.log('📝 Parsing LinkedIn Post');
console.log('📥 Input data keys:', Object.keys(inputData));

let linkedinPost = '';
let linkedinHashtags = [];

// Get article data from Extract Image URL node
let articleUrl = '';
let articleTitle = '';
let featuredImageUrl = '';

try {
  const extractNode = $('Extract Image URL');
  if (extractNode && extractNode.first()) {
    const data = extractNode.first().json;
    articleUrl = data.english_post_url || data.link || '';
    articleTitle = data.english_post_title || data.title?.raw || data.title || '';
    featuredImageUrl = data.featured_image_url || '';
  }
} catch (e) {
  console.log('⚠️ Could not get data from Extract Image URL:', e.message);
}

if (!articleUrl) {
  articleUrl = inputData.english_post_url || inputData.link || inputData.url || 'https://tax4us.co.il';
}

// EXTRACT AI RESPONSE - check multiple possible locations
let aiResponseText = '';

if (inputData.content) {
  aiResponseText = typeof inputData.content === 'string' ? inputData.content : JSON.stringify(inputData.content);
  console.log('📝 Found response in content field');
} else if (inputData.text) {
  aiResponseText = inputData.text;
  console.log('📝 Found response in text field');
} else if (inputData.message?.content) {
  if (Array.isArray(inputData.message.content)) {
    aiResponseText = inputData.message.content[0]?.text || inputData.message.content[0];
  } else {
    aiResponseText = inputData.message.content;
  }
  console.log('📝 Found response in message.content field');
} else if (inputData.response) {
  aiResponseText = inputData.response;
  console.log('📝 Found response in response field');
} else if (inputData.output) {
  aiResponseText = inputData.output;
  console.log('📝 Found response in output field');
} else if (typeof inputData === 'string') {
  aiResponseText = inputData;
  console.log('📝 Input is direct string');
}

console.log('📝 AI Response preview:', String(aiResponseText).substring(0, 300));

// Try to parse the AI response as JSON
let parsed = null;
if (aiResponseText) {
  let cleanText = String(aiResponseText).trim();
  cleanText = cleanText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '');

  try {
    parsed = JSON.parse(cleanText);
    console.log('✅ Successfully parsed AI JSON response');
  } catch (e) {
    console.log('⚠️ Could not parse as JSON, trying regex extraction...');
    const jsonMatch = cleanText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        parsed = JSON.parse(jsonMatch[0]);
        console.log('✅ Extracted and parsed JSON from text');
      } catch (e2) {
        console.log('⚠️ Regex extraction also failed');
        // Treat as plain text post
        linkedinPost = cleanText;
        console.log('📝 Using raw text as LinkedIn post');
      }
    } else {
      // Treat as plain text post
      linkedinPost = cleanText;
      console.log('📝 Using raw text as LinkedIn post');
    }
  }
}

// Check if fields are directly on inputData
if (!parsed && inputData.linkedin_post) {
  parsed = inputData;
  console.log('📝 Using inputData directly (already has linkedin_post)');
}

// Extract fields from parsed response
if (parsed) {
  linkedinPost = parsed.linkedin_post || parsed.linkedinPost || parsed.post || '';
  linkedinHashtags = parsed.linkedin_hashtags || parsed.hashtags || ['#USTax', '#ExpatTax', '#TaxPlanning', '#USExpats', '#IsraelTax'];
  console.log('✅ Extracted LinkedIn post from parsed JSON');
}

if (!Array.isArray(linkedinHashtags)) {
  linkedinHashtags = ['#USTax', '#ExpatTax', '#TaxPlanning', '#USExpats', '#IsraelTax'];
}

// Detect title-only posts
const isTitleOnly = (post, title) => {
  if (!post || !title) return false;
  const cleanPost = post.toLowerCase().replace(/https?:\/\/[^\s]+/gi, '').replace(/[#@]\w+/g, '').trim();
  const cleanTitle = title.toLowerCase().trim();
  if (cleanPost === cleanTitle) return true;
  if (cleanPost.length < 50 && cleanTitle.includes(cleanPost.substring(0, 30))) return true;
  return false;
};

// Generate fallback if needed
const generateFallback = () => {
  return `For US expats in Israel, navigating cross-border tax obligations requires careful attention to detail.\n\nKey considerations:\n→ Proper form selection and timing\n→ Understanding treaty provisions\n→ Documentation requirements\n\nGet the complete breakdown: ${articleUrl}\n\n#USTax #ExpatTax #TaxPlanning #USExpats #IsraelTax`;
};

if (!linkedinPost || linkedinPost.trim() === '' || isTitleOnly(linkedinPost, articleTitle)) {
  console.log('⚠️ LinkedIn post is empty or title-only - generating fallback');
  linkedinPost = generateFallback();
}

// Ensure URL is included
const urlPattern = /https?:\/\/[^\s]+/i;
if (!urlPattern.test(linkedinPost)) {
  console.log('⚠️ Adding missing URL to LinkedIn post');
  linkedinPost = linkedinPost + '\n\n' + articleUrl;
}

// Ensure hashtags are included
if (!linkedinPost.includes('#')) {
  console.log('⚠️ Adding hashtags to LinkedIn post');
  linkedinPost = linkedinPost + '\n\n' + linkedinHashtags.join(' ');
}

console.log('✅ LinkedIn post length:', linkedinPost.length);
console.log('✅ LinkedIn post preview:', linkedinPost.substring(0, 100));

return [{
  json: {
    ...inputData,
    linkedin_post: linkedinPost,
    linkedin_hashtags: linkedinHashtags,
    article_url: articleUrl,
    english_post_url: articleUrl,
    featured_image_url: featuredImageUrl || '',
    _parsed: !!parsed,
    _linkedin_validated: true
  }
}];

