// Parse bilingual Facebook post from AI output
// Format per Ben: כותרת בעברית -> טיזר עברית -> links

const inputData = $input.first().json;

console.log('📝 Parsing Bilingual Facebook Post');

let hebrewHeadline = '';
let hebrewTeaser = '';
let hebrewUrl = '';
let englishUrl = '';
let fullPost = '';

// Get URLs from input data first (if available)
hebrewUrl = inputData.link || inputData.hebrew_post_url || inputData.hebrewUrl || '';
englishUrl = inputData.english_post_url || inputData.englishUrl || inputData.article_url || '';

// If not in input, try to get from workflow nodes (with timeout protection)
if (!hebrewUrl || !englishUrl) {
  try {
    // Try Fetch Hebrew Post for Hebrew URL
    if (!hebrewUrl) {
      const fetchItems = $('Fetch Hebrew Post').all();
      if (fetchItems && fetchItems.length > 0 && fetchItems[0].json) {
        hebrewUrl = fetchItems[0].json.link || '';
        console.log('✅ Got Hebrew URL from Fetch node');
      }
    }

    // Try Link node for English URL
    if (!englishUrl) {
      const linkItems = $('Link Polylang Translations1').all();
      if (linkItems && linkItems.length > 0 && linkItems[0].json) {
        englishUrl = linkItems[0].json.english_post_url || linkItems[0].json.link || '';
        console.log('✅ Got English URL from Link node');
      }
    }
  } catch (e) {
    console.log('⚠️ Could not fetch URLs from nodes:', e.message);
  }
}

console.log('📎 Hebrew URL:', hebrewUrl);
console.log('📎 English URL:', englishUrl);

// DECODE URLs if they are URL-encoded
if (hebrewUrl && hebrewUrl.includes('%')) {
  try {
    hebrewUrl = decodeURIComponent(hebrewUrl);
  } catch (e) {}
}

if (englishUrl && englishUrl.includes('%')) {
  try {
    englishUrl = decodeURIComponent(englishUrl);
  } catch (e) {}
}

// EXTRACT AI RESPONSE - check multiple possible locations
let aiResponseText = '';

if (inputData.content) {
  aiResponseText = typeof inputData.content === 'string' ? inputData.content : JSON.stringify(inputData.content);
} else if (inputData.text) {
  aiResponseText = inputData.text;
} else if (inputData.message?.content) {
  if (Array.isArray(inputData.message.content)) {
    aiResponseText = inputData.message.content[0]?.text || inputData.message.content[0];
  } else {
    aiResponseText = inputData.message.content;
  }
} else if (inputData.response) {
  aiResponseText = inputData.response;
} else if (inputData.output) {
  aiResponseText = inputData.output;
} else if (typeof inputData === 'string') {
  aiResponseText = inputData;
}

// Try to parse the AI response as JSON
let parsed = null;
if (aiResponseText) {
  let cleanText = String(aiResponseText).trim();
  cleanText = cleanText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '');

  try {
    parsed = JSON.parse(cleanText);
  } catch (e) {
    const jsonMatch = cleanText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        parsed = JSON.parse(jsonMatch[0]);
      } catch (e2) {}
    }
  }
}

// Check if fields are directly on inputData
if (!parsed && inputData.hebrew_headline) {
  parsed = inputData;
}

// Extract fields from parsed response
if (parsed) {
  hebrewHeadline = parsed.hebrew_headline || '';
  hebrewTeaser = parsed.hebrew_teaser || '';
  if (!hebrewUrl && parsed.hebrew_url) hebrewUrl = parsed.hebrew_url;
  if (!englishUrl && parsed.english_url) englishUrl = parsed.english_url;
}

// Use fallbacks if needed
if (!hebrewHeadline) {
  hebrewHeadline = '💰 חדשות מס חשובות לאמריקאים בישראל';
}

if (!hebrewTeaser) {
  hebrewTeaser = 'למידע נוסף קראו את המאמר המלא.';
}

// Construct full post per Ben's format
fullPost = `${hebrewHeadline}\n\n${hebrewTeaser}\n\n🔗 לקריאה בעברית: ${hebrewUrl}\n🔗 Read in English: ${englishUrl}`;

return [{
  json: {
    ...inputData,
    hebrew_headline: hebrewHeadline,
    hebrew_teaser: hebrewTeaser,
    hebrew_url: hebrewUrl,
    english_url: englishUrl,
    facebook_post: fullPost,
    _parsed: !!parsed,
    _urls_verified: !!(hebrewUrl && englishUrl)
  }
}];

